import React, { useState } from 'react';
import { NotesProvider } from './context/NotesContext';
import Sidebar from './components/Layout/Sidebar';
import SplitLayout from './components/Layout/SplitLayout';
import TopBar from './components/UI/TopBar';
import ErrorBoundary from './components/ErrorBoundary';
import { useNotes } from './context/NotesContext';
import './styles/main.css';

function AppContent() {
  const { currentNote } = useNotes();
  const [showEditor, setShowEditor] = useState(false);

  const handleNoteSelect = () => {
    setShowEditor(true);
  };

  const handleBack = () => {
    setShowEditor(false);
  };

  return (
    <div className="app-container">
      {/* Mobile: Show either sidebar or editor, Desktop: Show both */}
      <div className="mobile-layout">
        <div className={`mobile-sidebar ${!showEditor ? 'mobile-sidebar--visible' : 'mobile-sidebar--hidden'}`}>
          <Sidebar onNoteSelect={handleNoteSelect} />
        </div>
        <div className={`mobile-editor ${showEditor ? 'mobile-editor--visible' : 'mobile-editor--hidden'}`}>
          {currentNote ? (
            <SplitLayout onBack={handleBack} />
          ) : (
            <div className="mobile-empty-state">
              <div className="empty-state-icon">Select a note</div>
            </div>
          )}
        </div>
      </div>

      {/* Desktop layout - always show both */}
      <div className="desktop-layout">
        <Sidebar />
        {currentNote && <SplitLayout />}
      </div>
    </div>
  );
}

function App() {
  return (
    <ErrorBoundary>
      <NotesProvider>
        <AppContent />
      </NotesProvider>
    </ErrorBoundary>
  );
}

export default App;
